from flask import Flask, request, jsonify, make_response, redirect
import jwt

app = Flask(__name__)

def extract_user_claims(token):
    try:
        claims = jwt.decode(token, options={"verify_signature": False})
        return claims
    except jwt.InvalidTokenError:
        return None

@app.route('/<path:backend_service>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def gateway(backend_service):
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return make_response(jsonify({"error": "Authorization header is missing."}), 401)
    
    token = auth_header.split(" ")[1]
    claims = extract_user_claims(token)
    
    if not claims:
        return make_response(jsonify({"error": "Invalid token."}), 401)
    
    # Forward Request to Backend Service
    # Example - Just printing details as placeholder to show extraction and redirection
    # Actual implementation would involve HTTP calls to forward the request.
    print("Forwarding to service:", backend_service)
    print("User Claims:", claims)
    
    return jsonify({"message": "Request forwarded successfully.", "claims": claims})

if __name__ == '__main__':
    app.run(debug=True)